package com.example.helloworldapi;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class HelloWorldApiApplication {

    public static void main(String[] args) {
        SpringApplication app = new SpringApplication(HelloWorldApiApplication.class);
        String serverPort = System.getenv("SERVER_PORT");
        if (serverPort != null && !serverPort.isBlank()) {
            app.setDefaultProperties(java.util.Map.of("server.port", serverPort));
        }
        app.run(args);
    }
}

package com.example.helloworldapi;

import java.util.Map;

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class HelloController {

    @GetMapping("/")
    public Map<String, String> hello(@RequestParam(name = "name", defaultValue = "") String name) {
        String trimmedName = name.trim();
        String resolvedName = trimmedName.isEmpty() ? "World" : trimmedName;
        return Map.of("message", "Hello " + resolvedName + "!");
    }
}
